<span class="line">                    <span class="token class-name">Text</span><span class="token punctuation">.</span><span class="token function">literal</span><span class="token punctuation">(</span><span class="token string">&quot;欢迎来到服务器！&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
